        Self.getUpsellFlag = function(upsellBEFlag) {
            var upsellFlag = [];
            if (defaults.isVrVideoValue) {
                upsellFlag = (upsellBEFlag && !defaults.premiumFlag) ? [2160] : [];
            } else {
                upsellFlag = (upsellBEFlag) ? [1080] : [];
